class Solution {
    public int numberOfWays(int n, int x) {
        int MOD = (int)1e9 + 7;
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j * j <= i; j++) {
                if (Math.pow(j, x) <= i) {
                    dp[i] = (dp[i] + dp[(int)(i - Math.pow(j, x))]) % MOD;
                }
            }
        }
        return dp[n];
    }
}
